SELECT

,MDD.DICT_LABEL AS STATUS_TEXT
FROM T_PRD_ODD_WORK_PLAN TPDWP
LEFT JOIN M_DICT_DATA MDD ON MDD.DICT_TYPE = 'ODD_STATUS' AND MDD.DICT_VALUE = TPDWP.STATUS


        AND TPDWP.STATUS = #{status, jdbcType=VARCHAR}


        AND TPDWP.ODD_TYPE = #{defaultOddType, jdbcType=VARCHAR}


        AND TPDWP.ODD_TYPE = #{oddType, jdbcType=VARCHAR}


        AND TPDWP.WORK_DEPT_ID IN

            #{id, jdbcType=VARCHAR}



        AND TPDWP.WORK_DEPT_ID = #{deptNo, jdbcType=VARCHAR}


        AND TPDWP.CREATE_FROM_DEPT IN

            #{id, jdbcType=BIGINT}



        AND TO_CHAR(TPDWP.CREATE_TIME,'YYYY-MM-DD') >= #{searchStartTime}


        AND TO_CHAR(TPDWP.CREATE_TIME,'YYYY-MM-DD') <= #{searchEndTime}



        AND TPDWP.ODD_PLAN_NO like #{oddPlanNo_like, jdbcType=VARCHAR}



        AND TPDWP.WORK_CONTENT like #{workContent_like, jdbcType=VARCHAR}


        AND TPDWP.CREATE_FROM_DEPT IN

            #{id, jdbcType=BIGINT}



        AND TPDWP.REJECT_TIME IS NOT NULL


        AND TPDWP.REJECT_TIME IS NULL


ORDER BY TPDWP.CREATE_TIME DESC

