mapper.select:
SELECT OWP.ID,OWP.ODD_PLAN_NO,OWPD.REPORT_START_TIME,OWPD.REPORT_END_TIME FROM T_PRD_ODD_WORK_PLAN OWP INNER JOIN T_PRD_ODD_WORK_PLAN_DETAIL OWPD ON OWP.ID = OWPD.ODD_PLAN_ID WHERE OWP.STATUS != '99' AND OWPD.REPORT_END_TIME IS NOT NULL AND OWPD.REPORT_START_TIME IS NOT NULL AND FIND_IN_SET(#{macId, jdbcType=VARCHAR},OWP.MAC_ID) > 0
AND OWP.ID != #{oddId, jdbcType=BIGINT}
AND ( (#{startTime, jdbcType=DATE} >= OWPD.REPORT_START_TIME AND #{startTime, jdbcType=DATE} < OWPD.REPORT_END_TIME) OR (#{endTime, jdbcType=DATE} > OWPD.REPORT_START_TIME AND #{endTime, jdbcType=DATE} <= OWPD.REPORT_END_TIME) OR ( #{startTime, jdbcType=DATE} <= OWPD.REPORT_START_TIME AND #{endTime, jdbcType=DATE} >= OWPD.REPORT_END_TIME ) )

SELECT OWP.ID,OWP.ODD_PLAN_NO,OWPD.REPORT_START_TIME,OWPD.REPORT_END_TIME FROM T_PRD_ODD_WORK_PLAN OWP INNER JOIN T_PRD_ODD_WORK_PLAN_DETAIL OWPD ON OWP.ID = OWPD.ODD_PLAN_ID WHERE OWP.STATUS != '99' AND OWPD.HOUR_METER_START IS NOT NULL AND OWPD.HOUR_METER_END IS NOT NULL AND FIND_IN_SET(#{macId, jdbcType=VARCHAR},OWP.MAC_ID) > 0
AND OWP.ID != #{oddId, jdbcType=BIGINT}
AND ( ( #{startHour, jdbcType=DECIMAL} >= OWPD.HOUR_METER_START AND #{startHour, jdbcType=DECIMAL} <= OWPD.HOUR_METER_END) OR ( #{endHour, jdbcType=DECIMAL} >= OWPD.HOUR_METER_START AND #{endHour, jdbcType=DECIMAL} <= OWPD.HOUR_METER_END) OR ( #{startHour, jdbcType=DECIMAL} <= OWPD.HOUR_METER_START AND #{endHour, jdbcType=DECIMAL} >= OWPD.HOUR_METER_END ) )

SELECT
ID,USER_NAME,
(      SELECT ID FROM (
SELECT ID,DEPT_LEVEL,DEPT_NAME FROM SYS_DEPT
START WITH ID = #{deptId, jdbcType=VARCHAR}

CONNECT BY PRIOR  PARENT_ID   = ID
) WHERE DEPT_LEVEL IN (1)
) DEPT_ID,
(      SELECT DEPT_NAME    FROM (
SELECT ID,DEPT_LEVEL,DEPT_NAME FROM SYS_DEPT
START WITH ID = #{deptId, jdbcType=VARCHAR}

CONNECT BY PRIOR  PARENT_ID   = ID
) WHERE DEPT_LEVEL IN (1)
) DEPT_NAME
FROM SYS_USER sus

select su.id,su.USER_NAME,su.DEPT_ID,sd.DEPT_NAME from SYS_USER su
LEFT JOIN SYS_DEPT sd on sd.id = su.DEPT_ID
where su.id = #{userId}
